div.script:
(function() {
    var statusData = {
        'New': ,
        'Assigned': ,
        'In Progress': ,
        'Resolved': ,
        'Closed': ,
        'Cancelled': 
    };
    var ctx = document.getElementById('statusChart');
    if (ctx) {
        new Chart(ctx, {
            type: 'doughnut',
            data: {
                labels: Object.keys(statusData),
                datasets: [{
                    data: Object.values(statusData),
                    backgroundColor: ['#6c757d', '#007bff', '#ffc107', '#17a2b8', '#28a745', '#dc3545']
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true
            }
        });
    }
})();

(function() {
    var priorityData = {
        'Low': ,
        'Medium': ,
        'High': ,
        'Urgent': 
    };
    var ctx2 = document.getElementById('priorityChart');
    if (ctx2) {
        new Chart(ctx2, {
            type: 'bar',
            data: {
                labels: Object.keys(priorityData),
                datasets: [{
                    label: 'Tickets',
                    data: Object.values(priorityData),
                    backgroundColor: ['#6c757d', '#17a2b8', '#ffc107', '#dc3545']
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true,
                scales: {
                    y: {
                        beginAtZero: true
                    }
                }
            }
        });
    }
})();
